using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    public string Category { get; set; } = string.Empty;

    public string Description { get; set; } = string.Empty;

    [Required, MinLength(1, ErrorMessage = "At least one ingredient is required.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required, MinLength(1, ErrorMessage = "At least one step is required.")]
    public string Steps { get; set; } = string.Empty;

    public string Author { get; set; } = "Community";

    public List<int> Ratings { get; } = [];

    public double AverageRating =>
        Ratings.Count == 0 ? 0 : Math.Round(Ratings.Average(), 1);

    public int RatingCount => Ratings.Count;
}

using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class RecipeSubmission
{
    [Required(ErrorMessage = "Title is required.")]
    [StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "A short description is required.")]
    [StringLength(300, ErrorMessage = "Description must be 300 characters or fewer.")]
    public string Description { get; set; } = string.Empty;

    [Required(ErrorMessage = "Ingredients are required.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Steps are required.")]
    public string Steps { get; set; } = string.Empty;

    [Required(ErrorMessage = "Author name is required.")]
    [StringLength(50)]
    public string Author { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public static readonly string[] Categories =
        ["Breakfast", "Lunch", "Dinner", "Desserts", "Snacks", "Beverages"];

    public RecipeService()
    {
        _recipes = CreateSeedData();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public IReadOnlyList<Recipe> GetAll() => _recipes.AsReadOnly();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase))
                .ToList()
                .AsReadOnly();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        ArgumentOutOfRangeException.ThrowIfLessThan(stars, 1);
        ArgumentOutOfRangeException.ThrowIfGreaterThan(stars, 5);

        var recipe = GetById(recipeId);
        recipe?.Ratings.Add(stars);
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = submission.Description,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            Author = submission.Author
        };
        _recipes.Add(recipe);
        return recipe;
    }

    private static List<Recipe> CreateSeedData()
    {
        var recipes = new List<Recipe>
        {
            new()
            {
                Id = 1,
                Title = "Classic Pancakes",
                Category = "Breakfast",
                Description = "Fluffy golden pancakes perfect for a lazy weekend morning.",
                Ingredients = "1½ cups all-purpose flour\n2 tbsp sugar\n1 tbsp baking powder\n¼ tsp salt\n1¼ cups milk\n1 egg\n3 tbsp melted butter\n1 tsp vanilla extract",
                Steps = "1. Whisk flour, sugar, baking powder, and salt in a bowl.\n2. In another bowl, combine milk, egg, melted butter, and vanilla.\n3. Pour wet ingredients into dry; stir until just combined (lumps are fine).\n4. Heat a non-stick pan over medium heat; lightly grease.\n5. Pour ¼ cup batter per pancake; cook until bubbles form on surface.\n6. Flip and cook another 1–2 minutes until golden.",
                Author = "Chef Maria"
            },
            new()
            {
                Id = 2,
                Title = "Avocado Toast",
                Category = "Breakfast",
                Description = "Simple, healthy, and endlessly customizable.",
                Ingredients = "2 slices sourdough bread\n1 ripe avocado\n1 tbsp lemon juice\nSalt and pepper to taste\nRed pepper flakes\nOptional: poached egg",
                Steps = "1. Toast the sourdough slices until golden and crisp.\n2. Halve the avocado, remove pit, and scoop flesh into a bowl.\n3. Mash with lemon juice, salt, and pepper.\n4. Spread onto toast and top with red pepper flakes.\n5. Add a poached egg on top if desired.",
                Author = "Chef Maria"
            },
            new()
            {
                Id = 3,
                Title = "Caesar Salad Wrap",
                Category = "Lunch",
                Description = "All the flavors of a Caesar salad in a portable wrap.",
                Ingredients = "2 large flour tortillas\n2 cups chopped romaine lettuce\n1 cup grilled chicken strips\n¼ cup shaved Parmesan\n¼ cup Caesar dressing\n½ cup croutons",
                Steps = "1. Warm tortillas in a dry skillet for 30 seconds each side.\n2. Toss lettuce, chicken, Parmesan, and croutons with dressing.\n3. Divide mixture between tortillas.\n4. Fold in sides and roll tightly.\n5. Slice in half diagonally to serve.",
                Author = "Chef Alex"
            },
            new()
            {
                Id = 4,
                Title = "Tomato Basil Soup",
                Category = "Lunch",
                Description = "A velvety, comforting classic ready in 30 minutes.",
                Ingredients = "2 tbsp olive oil\n1 onion, diced\n3 cloves garlic, minced\n2 cans (28 oz) crushed tomatoes\n1 cup vegetable broth\n½ cup fresh basil leaves\n½ cup heavy cream\nSalt and pepper",
                Steps = "1. Heat olive oil in a pot over medium heat; sauté onion until soft.\n2. Add garlic and cook 1 minute.\n3. Add crushed tomatoes and broth; bring to a simmer for 15 minutes.\n4. Stir in basil and blend until smooth with an immersion blender.\n5. Stir in cream, season with salt and pepper, and serve.",
                Author = "Chef Alex"
            },
            new()
            {
                Id = 5,
                Title = "Lemon Herb Roast Chicken",
                Category = "Dinner",
                Description = "Juicy roast chicken with a crispy, herbed skin.",
                Ingredients = "1 whole chicken (4 lbs)\n2 lemons\n4 cloves garlic\nFresh rosemary and thyme sprigs\n3 tbsp olive oil\nSalt and pepper\n1 lb baby potatoes, halved",
                Steps = "1. Preheat oven to 425°F (220°C).\n2. Pat chicken dry; season inside and out with salt and pepper.\n3. Stuff cavity with halved lemons, garlic, and half the herbs.\n4. Rub outside with olive oil; scatter remaining herbs on top.\n5. Surround with baby potatoes in a roasting pan.\n6. Roast 1 hour 15 minutes until juices run clear (165°F internal).\n7. Rest 10 minutes before carving.",
                Author = "Chef Thomas"
            },
            new()
            {
                Id = 6,
                Title = "Spaghetti Carbonara",
                Category = "Dinner",
                Description = "An authentic Roman pasta dish — no cream needed.",
                Ingredients = "1 lb spaghetti\n6 oz guanciale or pancetta, diced\n4 egg yolks\n1 whole egg\n1 cup grated Pecorino Romano\nFreshly cracked black pepper",
                Steps = "1. Cook spaghetti in salted boiling water until al dente; reserve 1 cup pasta water.\n2. Cook guanciale in a large skillet over medium heat until crispy.\n3. Whisk egg yolks, whole egg, and Pecorino together in a bowl.\n4. Drain pasta and add to the skillet (off heat).\n5. Pour egg mixture over pasta; toss quickly, adding pasta water as needed.\n6. Serve immediately with extra Pecorino and black pepper.",
                Author = "Chef Thomas"
            },
            new()
            {
                Id = 7,
                Title = "Chocolate Lava Cake",
                Category = "Desserts",
                Description = "Individual cakes with a molten chocolate center.",
                Ingredients = "4 oz dark chocolate\n½ cup unsalted butter\n1 cup powdered sugar\n2 eggs\n2 egg yolks\n6 tbsp all-purpose flour\nButter and cocoa for ramekins",
                Steps = "1. Preheat oven to 425°F (220°C). Butter and dust 4 ramekins with cocoa.\n2. Melt chocolate and butter together; stir in powdered sugar.\n3. Whisk in eggs and yolks, then fold in flour.\n4. Divide batter among ramekins.\n5. Bake 12–14 minutes until edges are firm but center is soft.\n6. Let stand 1 minute, then invert onto plates. Serve immediately.",
                Author = "Chef Sophie"
            },
            new()
            {
                Id = 8,
                Title = "Spiced Nuts Mix",
                Category = "Snacks",
                Description = "Sweet and spicy roasted nuts — perfect for parties.",
                Ingredients = "2 cups mixed nuts (almonds, cashews, pecans)\n2 tbsp melted butter\n2 tbsp brown sugar\n1 tsp cumin\n½ tsp cayenne pepper\n1 tsp salt",
                Steps = "1. Preheat oven to 325°F (165°C).\n2. Toss nuts with melted butter.\n3. Mix brown sugar, cumin, cayenne, and salt; sprinkle over nuts and toss.\n4. Spread on a baking sheet in a single layer.\n5. Bake 20 minutes, stirring halfway.\n6. Cool completely before serving — they crisp as they cool.",
                Author = "Chef Sophie"
            },
            new()
            {
                Id = 9,
                Title = "Mango Lassi",
                Category = "Beverages",
                Description = "A refreshing Indian yogurt drink, naturally sweet.",
                Ingredients = "1 cup ripe mango chunks (fresh or frozen)\n1 cup plain yogurt\n½ cup cold milk\n2 tbsp sugar or honey\n¼ tsp cardamom powder\nIce cubes",
                Steps = "1. Combine mango, yogurt, milk, sugar, and cardamom in a blender.\n2. Blend until smooth.\n3. Add ice cubes and blend briefly.\n4. Pour into glasses and serve chilled.\n5. Optionally garnish with a pinch of cardamom or saffron strands.",
                Author = "Chef Priya"
            },
        };

        // Add some initial ratings
        recipes[0].Ratings.AddRange([5, 4, 5, 4, 5]);
        recipes[1].Ratings.AddRange([4, 4, 3]);
        recipes[2].Ratings.AddRange([5, 5, 4]);
        recipes[4].Ratings.AddRange([5, 5, 5, 5, 4]);
        recipes[5].Ratings.AddRange([5, 4, 5, 5]);
        recipes[6].Ratings.AddRange([5, 5, 5, 4, 5]);
        recipes[7].Ratings.AddRange([4, 3, 4]);
        recipes[8].Ratings.AddRange([5, 4, 4, 5]);

        return recipes;
    }
}

