@rendermode InteractiveServer

<div class="star-rating">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= DisplayRating ? "filled" : "")"
                  @onclick="() => Rate(star)"
                  @onmouseover="() => _hover = star"
                  @onmouseout="() => _hover = 0"
                  title="Rate @star star@(star > 1 ? "s" : "")">
                @(star <= DisplayRating ? "★" : "☆")
            </span>
        }
    </div>
    <span class="rating-info">
        @if (AverageRating > 0)
        {
            <text>@AverageRating ⁄ 5 (@RatingCount @(RatingCount == 1 ? "rating" : "ratings"))</text>
        }
        else
        {
            <text>No ratings yet</text>
        }
    </span>
