<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav class="breadcrumb">
    <a href="/">Home</a> / <span>Submit Recipe</span>
</nav>

<h1>Submit a Recipe</h1>
<p class="subtitle">Share your favorite recipe with the RecipeHub community.</p>

@if (_submitted)
{
    <div class="success-message">
        <h2>🎉 Recipe Submitted!</h2>
        <p>Your recipe "<strong>@_submittedTitle</strong>" has been added.</p>
        <div class="success-actions">
            <a href="/recipe/@_submittedId" class="btn-primary">View Recipe</a>
            <button class="btn-secondary" @onclick="ResetForm">Submit Another</button>
        </div>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" class="recipe-form" FormName="SubmitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category">
                <option value="">— Select a category —</option>
                @foreach (var cat in RecipeService.Categories)
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
            <ValidationMessage For="() => _model.Category" />
        </div>

        <div class="form-group">
            <label for="description">Short Description</label>
            <InputTextArea id="description" @bind-Value="_model.Description" rows="2"
                           placeholder="A brief description of your recipe" />
            <ValidationMessage For="() => _model.Description" />
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" rows="6"
                           placeholder="One ingredient per line, e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => _model.Ingredients" />
        </div>

        <div class="form-group">
            <label for="steps">Steps</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" rows="6"
                           placeholder="One step per line, e.g.&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => _model.Steps" />
        </div>

        <div class="form-group">
            <label for="author">Your Name</label>
            <InputText id="author" @bind-Value="_model.Author" placeholder="Your name" />
            <ValidationMessage For="() => _model.Author" />
        </div>

        <button type="submit" class="btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission _model = new();
    private bool _submitted;
    private int _submittedId;
    private string _submittedTitle = string.Empty;

    private void HandleSubmit()
    {
        var recipe = Recipes.AddRecipe(_model);
        _submittedId = recipe.Id;
        _submittedTitle = recipe.Title;
        _submitted = true;
    }

    private void ResetForm()
    {
        _model = new RecipeSubmission();
        _submitted = false;
    }
}
