toolArgs.file_text:
@page "/category/{CategoryName}"
@using RecipeHub.Services

@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

@if (_recipes.Count == 0)
{
    <h1>@CategoryName</h1>
    <p>No recipes found in this category.</p>
    <a href="/">← Back to categories</a>
}
else
{
    <nav class="breadcrumb">
        <a href="/">Home</a> / <span>@CategoryName</span>
    </nav>

    <h1>@CategoryName Recipes</h1>
    <p class="subtitle">@_recipes.Count @(_recipes.Count == 1 ? "recipe" : "recipes") in this category</p>

    <div class="recipe-list">
        @foreach (var recipe in _recipes)
        {
            <a href="/recipe/@recipe.Id" class="recipe-card">
                <h3>@recipe.Title</h3>
                <p class="recipe-meta">
                    By @recipe.Author
                    @if (recipe.RatingCount > 0)
                    {
                        <text> · ★ @recipe.AverageRating (@recipe.RatingCount)</text>
                    }
                </p>
                <p>@recipe.Description</p>
            </a>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        var formatted = System.Globalization.CultureInfo.CurrentCulture.TextInfo
            .ToTitleCase(CategoryName.ToLower());
        CategoryName = formatted;
        _recipes = Recipes.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Components.Shared

@inject RecipeService Recipes

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found — RecipeHub</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="/">← Back to Home</a>
}
else
{
    <PageTitle>@_recipe.Title — RecipeHub</PageTitle>

    <nav class="breadcrumb">
        <a href="/">Home</a> /
        <a href="/category/@_recipe.Category.ToLower()">@_recipe.Category</a> /
        <span>@_recipe.Title</span>
    </nav>

    <article class="recipe-detail">
        <header>
            <h1>@_recipe.Title</h1>
            <p class="recipe-meta">By @_recipe.Author · @_recipe.Category</p>
            <p class="recipe-description">@_recipe.Description</p>
        </header>

        <section class="rating-section">
            <h2>Rate This Recipe</h2>
            <StarRating RecipeId="@_recipe.Id"
                        AverageRating="@_recipe.AverageRating"
                        RatingCount="@_recipe.RatingCount"
                        OnRated="HandleRating" />
        </section>

        <section class="ingredients-section">
            <h2>🥘 Ingredients</h2>
            <ul>
                @foreach (var line in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                {
                    <li>@line.Trim()</li>
                }
            </ul>
        </section>

        <section class="steps-section">
            <h2>📝 Steps</h2>
            <ol>
                @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                {
                    var text = System.Text.RegularExpressions.Regex.Replace(step.Trim(), @"^\d+\.\s*", "");
                    <li>@text</li>
                }
            </ol>
        </section>
    </article>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeHub.Models.Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = Recipes.GetById(Id);
    }

    private void HandleRating(int stars)
    {
        Recipes.AddRating(Id, stars);
        _recipe = Recipes.GetById(Id);
    }
}

